import { connection } from 'next/server'

export default async function ServerTimestamp() {
  // Ensure the timestamp is generated while handling the request, not at build time.
  await connection()

  const timestamp = new Date().toISOString()

  return (
    <p>
      Current server timestamp: <time dateTime={timestamp}>{timestamp}</time>
    </p>
  )
}

